function TaskDialog()
this:AddTalk("你好。")
this:AddTalk("有什么想去的地方吗？")
this:AddTalk("<p><n color=\"255,0,255,255\">最近开发了新的线路“万宝宫”。</n></p>");
this:AddTalk("<p><n color=\"255,255,255,0\">开放时间：21:00-23:00！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">玩家需要共同清理当层的怪物后才可进入下一层继续打宝！</n></p>");
this:AddTaskCmdItem("进入-万宝宫一层(0)", "v5150", 160103, 1)
this:AddCloseItem("离开")
end

